import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  SafeAreaView,
  StatusBar,
  Animated,
  KeyboardAvoidingView,
  Platform,
  useWindowDimensions,
} from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { countries } from '../data/countries';
import { cities } from '../data/cities';
import { animals } from '../data/categories';
import { TinderCard } from '../components/TinderCard';
import { GuessInput } from '../components/GuessInput';
import { Confetti } from '../components/Confetti';
import { AnimatedCounter } from '../components/AnimatedCounter';
import { hapticSuccess, hapticError, hapticMedium, hapticLight } from '../utils/haptics';
import { playSound } from '../utils/sounds';

type Phase = 'swiping' | 'guessing' | 'correct' | 'revealed';

const CATEGORY_CONTENT = {
  countries: {
    title: 'Ülkeler',
    items: countries,
  },
  cities: {
    title: 'Şehirler TR',
    items: cities,
  },
  animals: {
    title: 'Hayvanlar',
    items: animals,
  },
} as const;

const ANSWER_ALIASES: Record<string, string[]> = {
  // cities
  istanbul: ['i̇stanbul', 'constantinople', 'istanbul'],
  ankara: [],
  izmir: ['i̇zmir', 'smyrna'],
  antalya: [],
  bursa: [],
  trabzon: ['trebizond'],
  konya: [],
  kapadokya: ['cappadocia', 'nevşehir', 'nevsehir', 'kappadokya'],
  erzurum: [],
  gaziantep: ['antep'],
  // countries
  bhutan: ['butan'],
  izlanda: ['iceland'],
  'moğolistan': ['mogolistan', 'mongolistan'],
  slovenya: ['slovenia'],
  surinam: ['suriname'],
  vanuatu: [],
  'lihtenştayn': ['lihtenstayn', 'liechtenstein'],
  cibuti: ['djibouti'],
  nauru: [],
  andorra: [],
};

const TURKISH_CHAR_MAP: Record<string, string> = {
  ç: 'c',
  ğ: 'g',
  ı: 'i',
  ö: 'o',
  ş: 's',
  ü: 'u',
  â: 'a',
  î: 'i',
  û: 'u',
};

function normalizeAnswer(value: string): string {
  return value
    .trim()
    .toLocaleLowerCase('tr-TR')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[çğıöşüâîû]/g, (char) => TURKISH_CHAR_MAP[char] ?? char)
    .replace(/[^a-z0-9]/g, '');
}

function isCorrectGuess(guess: string, answer: string): boolean {
  const normalizedGuess = normalizeAnswer(guess);
  const accepted = [answer, ...(ANSWER_ALIASES[answer] ?? [])].map(normalizeAnswer);
  return accepted.includes(normalizedGuess);
}

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

interface Props {
  category: string;
  onBack: () => void;
}

export function GameScreen({ category, onBack }: Props) {
  const { width, height } = useWindowDimensions();
  const cardAreaHeight = height * 0.50;
  const cardWidth = Math.max(1, width - 40);
  const cardHeight = Math.max(240, cardAreaHeight);
  const gameContent = useMemo(() => {
    return CATEGORY_CONTENT[category as keyof typeof CATEGORY_CONTENT] ?? CATEGORY_CONTENT.countries;
  }, [category]);

  const [deck, setDeck] = useState(() => shuffle(gameContent.items));
  const [countryIndex, setCountryIndex] = useState(0);
  const [hintIndex, setHintIndex] = useState(0);
  const [phase, setPhase] = useState<Phase>('swiping');
  const [wrongCount, setWrongCount] = useState(0);
  const [shakeSignal, setShakeSignal] = useState(0);
  const [score, setScore] = useState(0);
  const [confettiTrigger, setConfettiTrigger] = useState(0);
  const [streak, setStreak] = useState(0);

  const resultSlide   = useRef(new Animated.Value(height)).current;
  const resultOpacity = useRef(new Animated.Value(0)).current;
  const streakScale   = useRef(new Animated.Value(1)).current;
  const stackFade     = useRef(new Animated.Value(0)).current;
  const bildimGlow    = useRef(new Animated.Value(0)).current;

  const country = deck[countryIndex % deck.length];
  const totalHints = country.hints.length;
  const isLastHint = hintIndex >= totalHints - 1;
  const visibleHints = country.hints.slice(hintIndex, hintIndex + 3);

  // Snap stack to invisible then fade in — runs on every hint change AND country change
  useEffect(() => {
    stackFade.setValue(0);
    Animated.timing(stackFade, { toValue: 1, duration: 120, useNativeDriver: true }).start();
  }, [countryIndex, hintIndex]);
  const pointsEarned = Math.max(5 - wrongCount, 1);
  // Turkish-aware capitalisation (handles ı → I, i → İ)
  const capitalised = country.answer.charAt(0).toLocaleUpperCase('tr-TR') + country.answer.slice(1);

  useEffect(() => {
    setDeck(shuffle(gameContent.items));
    setCountryIndex(0);
    setHintIndex(0);
    setPhase('swiping');
    setWrongCount(0);
    setShakeSignal(0);
    setScore(0);
    setStreak(0);
  }, [gameContent]);

  useEffect(() => {
    if (phase !== 'correct' && phase !== 'revealed') {
      resultSlide.setValue(height);
    }
  }, [height, phase, resultSlide]);

  useEffect(() => {
    const loop = Animated.loop(
      Animated.sequence([
        Animated.timing(bildimGlow, { toValue: 1, duration: 1100, useNativeDriver: true }),
        Animated.timing(bildimGlow, { toValue: 0, duration: 1100, useNativeDriver: true }),
      ])
    );
    loop.start();
    return () => loop.stop();
  }, [bildimGlow]);

  const showResult = useCallback((success: boolean) => {
    Animated.parallel([
      Animated.spring(resultSlide, {
        toValue: 0,
        tension: 65,
        friction: 12,
        useNativeDriver: true,
      }),
      Animated.timing(resultOpacity, {
        toValue: 1,
        duration: 300,
        useNativeDriver: true,
      }),
    ]).start();

    if (success) {
      setTimeout(() => setConfettiTrigger((c) => c + 1), 200);
    }
  }, [resultOpacity, resultSlide]);

  const hideResult = useCallback((cb: () => void) => {
    Animated.parallel([
      Animated.timing(resultSlide, {
        toValue: height,
        duration: 300,
        useNativeDriver: true,
      }),
      Animated.timing(resultOpacity, {
        toValue: 0,
        duration: 200,
        useNativeDriver: true,
      }),
    ]).start(cb);
  }, [height, resultOpacity, resultSlide]);

  const handleSwipeLeft = useCallback(() => {
    if (isLastHint) return;
    hapticLight();
    setHintIndex((i) => i + 1);
  }, [isLastHint]);

  const handleSwipeRight = useCallback(() => {
    hapticMedium();
    setPhase('guessing');
  }, []);

  const handleGuess = useCallback(
    (guess: string) => {
      if (isCorrectGuess(guess, country.answer)) {
        hapticSuccess();
        playSound('correct');
        const pts = pointsEarned;
        setScore((s) => s + pts);
        setStreak((s) => {
          const next = s + 1;
          Animated.sequence([
            Animated.spring(streakScale, { toValue: 1.4, tension: 200, friction: 6, useNativeDriver: true }),
            Animated.spring(streakScale, { toValue: 1, tension: 200, friction: 8, useNativeDriver: true }),
          ]).start();
          return next;
        });
        setPhase('correct');
        showResult(true);
        setTimeout(() => playSound('points'), 400);
      } else {
        hapticError();
        playSound('wrong');
        setWrongCount((c) => c + 1);
        setStreak(0);
        setShakeSignal((s) => s + 1);
        if (!isLastHint) setHintIndex((i) => i + 1);
      }
    },
    [country.answer, pointsEarned, isLastHint, showResult]
  );

  const handleNext = useCallback(() => {
    hideResult(() => {
      resultSlide.setValue(height);
      setCountryIndex((i) => {
        const next = i + 1;
        if (next >= deck.length) {
          // Reshuffle so the player doesn't see the same order again
          setDeck(shuffle(gameContent.items));
          return 0;
        }
        return next;
      });
      setHintIndex(0);
      setPhase('swiping');
      setWrongCount(0);
    });
  }, [height, hideResult, resultSlide, deck.length, gameContent.items]);

  const handleGiveUp = useCallback(() => {
    hapticMedium();
    setStreak(0);
    setHintIndex(totalHints - 1);
    setPhase('revealed');
    showResult(false);
  }, [totalHints, showResult]);

  return (
    <View style={styles.root}>
      <StatusBar barStyle="light-content" />
      <LinearGradient
        colors={['#0F1230', '#161A4A', '#0F1230']}
        style={StyleSheet.absoluteFill}
      />
      <View style={styles.orb1} />
      <View style={styles.orb2} />

      <SafeAreaView style={styles.safe}>
        {/* Header */}
        <View style={styles.header}>
          <TouchableOpacity
            onPress={() => { hapticLight(); onBack(); }}
            activeOpacity={0.75}
            style={styles.backBtn}
          >
            <Text style={styles.backIcon}>←</Text>
          </TouchableOpacity>

          <View style={styles.headerCenter}>
            <Text style={styles.headerTitle}>{gameContent.title}</Text>
            {streak >= 2 && (
              <Animated.View style={[styles.streakBadge, { transform: [{ scale: streakScale }] }]}>
                <Text style={styles.streakText}> {streak}</Text>
              </Animated.View>
            )}
          </View>

          <View style={styles.scorePill}>
            <Text style={styles.scoreLabel}>PUAN</Text>
            <AnimatedCounter value={score} style={styles.scoreValue} />
          </View>
        </View>

        {/* Card stack */}
        {(phase === 'swiping' || phase === 'guessing') && (
          <Animated.View style={[styles.cardArea, { height: cardHeight, opacity: stackFade }]}>
            {[...visibleHints].reverse().map((hint, reverseIdx) => {
              const stackIndex = visibleHints.length - 1 - reverseIdx;
              // Include position label in key so React always remounts when a card
              // moves from a background slot to the top slot (fixes typewriter re-trigger)
              const posLabel = stackIndex === 0 ? 'top' : 'bg';
              return (
                <TinderCard
                  key={`${countryIndex}-${hintIndex + stackIndex}-${posLabel}`}
                  hint={hint}
                  hintIndex={hintIndex + stackIndex}
                  totalHints={totalHints}
                  stackIndex={stackIndex}
                  isTop={stackIndex === 0}
                  cardWidth={cardWidth}
                  cardHeight={cardHeight}
                  screenWidth={width}
                  onSwipeLeft={handleSwipeLeft}
                  onSwipeRight={handleSwipeRight}
                />
              );
            })}
          </Animated.View>
        )}

        {/* Action bar */}
        <KeyboardAvoidingView
          behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
          style={styles.actionArea}
        >
          {phase === 'swiping' && (
            <View style={styles.swipeActions}>
              <View style={styles.actionRow}>
                {/* Sonraki ipucu */}
                <TouchableOpacity
                  style={[styles.skipBtn, isLastHint && styles.skipBtnDisabled]}
                  onPress={isLastHint ? undefined : () => { hapticLight(); handleSwipeLeft(); }}
                  activeOpacity={isLastHint ? 1 : 0.75}
                >
                  <LinearGradient
                    colors={isLastHint ? ['#1a1e2a', '#141820'] : ['#f97316', '#ea580c']}
                    start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }}
                    style={styles.skipBtnInner}
                  >
                    <LinearGradient
                      colors={['rgba(255,255,255,0.15)', 'rgba(255,255,255,0)']}
                      start={{ x: 0.5, y: 0 }} end={{ x: 0.5, y: 1 }}
                      style={StyleSheet.absoluteFill}
                      pointerEvents="none"
                    />
                    <Ionicons
                      name={isLastHint ? 'close-circle-outline' : 'flash-outline'}
                      size={22}
                      color={isLastHint ? 'rgba(255,255,255,0.2)' : '#fff'}
                    />
                    <Text style={[styles.skipLabel, isLastHint && styles.skipLabelDim]}>
                      {isLastHint ? 'Başka yok' : 'Sonraki'}
                    </Text>
                  </LinearGradient>
                </TouchableOpacity>

                {/* Bildim! — premium green with gloss overlay + pulsing glow */}
                <View style={styles.bildimWrap}>
                  <Animated.View
                    pointerEvents="none"
                    style={[
                      styles.bildimGlowRing,
                      {
                        opacity: bildimGlow.interpolate({ inputRange: [0, 1], outputRange: [0, 0.5] }),
                        transform: [{ scale: bildimGlow.interpolate({ inputRange: [0, 1], outputRange: [1, 1.06] }) }],
                      },
                    ]}
                  />
                  <TouchableOpacity
                    style={styles.bildimBtn}
                    onPress={() => { hapticMedium(); handleSwipeRight(); }}
                    activeOpacity={0.8}
                  >
                    <LinearGradient
                      colors={['#059669', '#10b981', '#34d399']}
                      start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }}
                      style={styles.bildimBtnInner}
                    >
                      {/* Top gloss sheen */}
                      <LinearGradient
                        colors={['rgba(255,255,255,0.18)', 'rgba(255,255,255,0)']}
                        start={{ x: 0.5, y: 0 }} end={{ x: 0.5, y: 1 }}
                        style={StyleSheet.absoluteFill}
                        pointerEvents="none"
                      />
                      <Ionicons name="create-outline" size={22} color="#fff" />
                      <Text style={styles.bildimLabel}>Bildim!</Text>
                    </LinearGradient>
                  </TouchableOpacity>
                </View>
              </View>

              {isLastHint && (
                <TouchableOpacity onPress={handleGiveUp} activeOpacity={0.7} style={styles.giveUpBtn}>
                  <Text style={styles.giveUpText}>Vazgeçtim — cevabı göster</Text>
                </TouchableOpacity>
              )}
            </View>
          )}

          {phase === 'guessing' && (
            <View style={styles.guessActions}>
              <View style={styles.guessHeaderRow}>
                <Text style={styles.guessTitle}>
                  {category === 'cities' ? 'Hangi şehir?' : 'Hangi ülke?'}
                </Text>
                {wrongCount > 0 && (
                  <View style={styles.wrongCounter}>
                    <Text style={styles.wrongCounterText}>{wrongCount} ✗</Text>
                  </View>
                )}
              </View>

              <GuessInput
                onSubmit={handleGuess}
                shakeSignal={shakeSignal}
                placeholder={category === 'cities' ? 'Şehrin adını yaz…' : 'Ülkenin adını yaz…'}
              />

              {wrongCount > 0 && (
                <View style={styles.wrongBanner}>
                  <Text style={styles.wrongBannerIcon}>✗</Text>
                  <Text style={styles.wrongBannerText}>
                    Yanlış!{isLastHint ? " Tüm ipuçları gösterildi." : " Yeni ipucu açıldı."}
                  </Text>
                </View>
              )}

              <TouchableOpacity onPress={() => setPhase('swiping')} activeOpacity={0.7}>
                <Text style={styles.backToClues}>← İpuçlarına dön</Text>
              </TouchableOpacity>
            </View>
          )}
        </KeyboardAvoidingView>
      </SafeAreaView>

      {/* Result sheet */}
      {(phase === 'correct' || phase === 'revealed') && (
        <Animated.View
          style={[
            styles.resultSheet,
            {
              transform: [{ translateY: resultSlide }],
              opacity: resultOpacity,
            },
          ]}
        >
          <LinearGradient
            colors={
              phase === 'correct'
                ? ['#0D2818', '#0A1F2E', '#0D0F1A']
                : ['#1A0A0A', '#0A1520', '#0D0F1A']
            }
            style={styles.resultSheetInner}
          >
            {/* Handle bar */}
            <View style={styles.handle} />

            {phase === 'correct' ? (
              <>
                <Text style={styles.resultEmoji}></Text>
                <Text style={styles.resultCorrectLabel}>DOĞRU!</Text>
                <Text style={styles.resultCountry}>{capitalised}</Text>

                <View style={styles.pointsRow}>
                  <LinearGradient
                    colors={['#7C3AED', '#4F46E5']}
                    start={{ x: 0, y: 0 }}
                    end={{ x: 1, y: 0 }}
                    style={styles.pointsBadge}
                  >
                    <Text style={styles.pointsBadgeText}>+{pointsEarned} puan</Text>
                  </LinearGradient>

                  {streak >= 2 && (
                    <View style={styles.streakResultBadge}>
                      <Text style={styles.streakResultText}> {streak} seri</Text>
                    </View>
                  )}
                </View>

                <TouchableOpacity onPress={handleNext} activeOpacity={0.85} style={styles.nextBtnWrap}>
                  <LinearGradient
                    colors={['#10b981', '#059669']}
                    start={{ x: 0, y: 0 }}
                    end={{ x: 1, y: 0 }}
                    style={styles.nextBtn}
                  >
                    <Text style={styles.nextBtnText}>
                      {category === 'cities' ? 'Sonraki Şehir →' : 'Sonraki Ülke →'}
                    </Text>
                  </LinearGradient>
                </TouchableOpacity>
              </>
            ) : (
              <>
                <Text style={styles.resultEmoji}></Text>
                <Text style={styles.resultRevealLabel}>CEVAP ŞUYDU</Text>
                <Text style={styles.resultCountry}>{capitalised}</Text>

                <TouchableOpacity onPress={handleNext} activeOpacity={0.85} style={styles.nextBtnWrap}>
                  <LinearGradient
                    colors={['#374151', '#4B5563']}
                    start={{ x: 0, y: 0 }}
                    end={{ x: 1, y: 0 }}
                    style={styles.nextBtn}
                  >
                    <Text style={styles.nextBtnText}>Sonrakini Dene →</Text>
                  </LinearGradient>
                </TouchableOpacity>
              </>
            )}
          </LinearGradient>
        </Animated.View>
      )}

      {/* Confetti layer */}
      <Confetti trigger={confettiTrigger} originX={width / 2} originY={height * 0.4} />
    </View>
  );
}

