    Animated.spring(enter, {
      toValue: 1, delay: 1100 + index * 130,
      tension: 55, friction: 11, useNativeDriver: true,
    }).start();
  }, [enter, index]);
  const ty = enter.interpolate({ inputRange: [0, 1], outputRange: [16, 0] });

  return (
