          {/* ── Footer ── */}
          <View style={s.footer}>
            <LinearGradient colors={['#6366f1', '#a855f7', '#ec4899']}
              start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={s.footerDash} />
