              start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={s.footerDash} />
          </View>

          <View style={{ height: 28 }} />
          </View>{/* end contentWrap */}
        </ScrollView>
      </SafeAreaView>
    </View>
  );
}

